     1→//! R-style formula parsing and design matrix specification
     2→//!
     3→//! This crate provides compile-time and run-time parsing of statistical formulas
     4→//! in the R format (e.g., `y ~ x1 + x2*x3`), compiling them into optimized
     5→//! design matrix generators.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use pest::iterators::Pair;
    11→use pest::Parser;
    12→use pest_derive::Parser;
    13→
    14→#[derive(Parser)]
    15→#[grammar = "formula.pest"]
    16→struct FormulaParser;
    17→
    18→/// Formula parsing errors
    19→#[derive(thiserror::Error, Debug)]
    20→pub enum FormulaError {
    21→    /// Parse error from pest
    22→    #[error("Formula parse error: {0}")]
    23→    Parse(String),
    24→    /// Semantic validation error
    25→    #[error("Formula validation error: {0}")]
    26→    Validation(String),
    27→}
    28→
    29→/// Abstract syntax tree representing a parsed statistical formula
    30→#[derive(Debug, Clone, PartialEq)]
    31→pub struct ModelSpec {
    32→    /// The response variable(s)
    33→    pub response: Vec<String>,
    34→    /// The predictor terms
    35→    pub terms: Vec<Term>,
    36→}
    37→
    38→/// A term in a statistical formula
    39→#[derive(Debug, Clone, PartialEq)]
    40→pub enum Term {
    41→    /// Intercept term
    42→    Intercept,
    43→    /// Variable name
    44→    Variable(String),
    45→    /// Interaction between terms
    46→    Interaction(Vec<Term>),
    47→    /// Function call (e.g., I(x^2), poly(x, 2))
    48→    Function {
    49→        /// Function name
    50→        name: String,
    51→        /// Function arguments
    52→        args: Vec<String>,
    53→    },
    54→}
    55→
    56→impl ModelSpec {
    57→    /// Create a simple formula with intercept
    58→    pub fn intercept_only(response: &str) -> Self {
    59→        Self {
    60→            response: vec![response.to_string()],
    61→            terms: vec![Term::Intercept],
    62→        }
    63→    }
    64→
    65→    /// Add a variable term
    66→    pub fn add_variable(&mut self, var: &str) {
    67→        self.terms.push(Term::Variable(var.to_string()));
    68→    }
    69→}
    70→
    71→/// Parse a formula string into a ModelSpec  
    72→pub fn parse_formula(formula: &str) -> Result<ModelSpec, FormulaError> {
    73→    let mut pairs = FormulaParser::parse(Rule::formula, formula)
    74→        .map_err(|e| FormulaError::Parse(e.to_string()))?;
    75→
